import hmac import hashlib import time
def sign_request(api_secret, method, path, body, timestamp): """ Create HMAC signature for API request """ message = f"{timestamp}.{method}.{path}.{body}" signature = hmac.new( api_secret.encode(), message.encode(), hashlib.sha256 ).hexdigest() return signature
# Request headers headers = { "X-API-Key": "pk_live_xxxxx", "X-Timestamp": str(int(time.time())), "X-Signature": sign_request(secret, "POST", "/v1/payments", body, timestamp), "Idempotency-Key": "unique-request-id" }

# OPA policy for service authorization package envoy.authz
import input.attributes.request.http as http_request import input.attributes.source.principal as source_principal
default allow = false
# Allow API gateway to access all services allow { source_principal == "spiffe://cluster.local/ns/api-gateway/sa/api-gateway" }
# Allow payments to access orders (for order status updates) allow { source_principal == "spiffe://cluster.local/ns/payments/sa/payments-processor" http_request.path == "/api/v1/orders/status" http_request.method == "PUT" }
# Allow inventory to access orders (read only) allow { source_principal == "spiffe://cluster.local/ns/inventory/sa/inventory-api" glob.match("/api/v1/orders/*", [], http_request.path) http_request.method == "GET" }

// iOS Keychain storage
class SecureStorage {
    func storeCredential(_ credential: Data, forKey key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: credential,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecAttrAccessControl as String: SecAccessControlCreateWithFlags(
                nil,
                kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                [.biometryAny, .devicePasscode],
                nil
            )!
        ]
        SecItemAdd(query as CFDictionary, nil)
    }
}

// Android EncryptedSharedPreferences
class SecureStorage(context: Context) {
    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .setUserAuthenticationRequired(true)
        .setUserAuthenticationParameters(
            300, // validity duration
            KeyProperties.AUTH_BIOMETRIC_STRONG or
            KeyProperties.AUTH_DEVICE_CREDENTIAL
        )
        .build()

    private val securePrefs = EncryptedSharedPreferences.create(
        context,
        "secure_prefs",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun storeCredential(key: String, value: String) {
        securePrefs.edit().putString(key, value).apply()
    }
}

// iOS certificate pinning with TrustKit
TrustKit.initSharedInstance(withConfiguration: [
    kTSKSwizzleNetworkDelegates: true,
    kTSKPinnedDomains: [
        "api.example.com": [
            kTSKEnforcePinning: true,
            kTSKIncludeSubdomains: true,
            kTSKPublicKeyHashes: [
                "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",
                "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="  // Backup pin
            ],
            kTSKReportUris: ["https://report.example.com/pin-failure"]
        ]
    ]
])

resource "auth0_tenant" "main" {
  friendly_name           = "YourApp Production"
  support_email           = "security@yourapp.com"
  default_directory       = "Username-Password-Authentication"
  session_lifetime        = 168
  idle_session_lifetime   = 72
}

resource "auth0_client" "web_app" {
  name                = "Web Application"
  app_type            = "spa"
  oidc_conformant     = true
  token_endpoint_auth_method = "none"
  callbacks           = ["https://app.yourapp.com/callback"]
  allowed_origins     = ["https://app.yourapp.com"]
  allowed_logout_urls = ["https://app.yourapp.com"]
  jwt_configuration {
    alg                 = "RS256"
    lifetime_in_seconds = 3600
  }
  refresh_token {
    rotation_type                = "rotating"
    expiration_type              = "expiring"
    token_lifetime               = 2592000
    idle_token_lifetime          = 1296000
  }
  grant_types = ["authorization_code", "refresh_token"]
}

resource "auth0_guardian" "mfa" {
  policy = "all-applications"
  webauthn_platform { enabled = true }
  webauthn_roaming { enabled = true }
  otp { enabled = true }
}

# FastAPI OIDC configuration from authlib.integrations.starlette_client import OAuth from fastapi import FastAPI, Depends, HTTPException from starlette.config import Config
config = Config(".env") oauth = OAuth(config)
# OIDC provider configuration oauth.register( name="oidc", server_metadata_url="https://auth.yourapp.com/.well-known/openid-configuration", client_id=config("OIDC_CLIENT_ID"), client_secret=config("OIDC_CLIENT_SECRET"), client_kwargs={ "scope": "openid profile email", "code_challenge_method": "S256", # PKCE }, )
# Token verification from jose import jwt, JWTError from functools import lru_cache import httpx
@lru_cache() def get_jwks(): """Fetch and cache JWKS""" response = httpx.get("https://auth.yourapp.com/.well-known/jwks.json") return response.json()
async def verify_token(token: str) -> dict: """Verify JWT token""" try: jwks = get_jwks() unverified_header = jwt.get_unverified_header(token)
# Find the key rsa_key = None for key in jwks["keys"]: if key["kid"] == unverified_header["kid"]: rsa_key = key break
if not rsa_key: raise HTTPException(status_code=401, detail="Invalid token")
payload = jwt.decode( token, rsa_key, algorithms=["RS256"], audience="https://api.yourapp.com", issuer="https://auth.yourapp.com/", options={ "verify_exp": True, "verify_iat": True, "verify_nbf": True, } ) return payload
except JWTError as e: raise HTTPException(status_code=401, detail=f"Token validation failed: {e}")

package api.authz

import rego.v1

default allow := false

# Allow admins full access
allow if {
    input.user.roles[_] == "admin"
}

# Allow users to read their own data
allow if {
    input.method == "GET"
    input.path = ["api", "v1", "users", user_id]
    input.user.id == user_id
}

# Allow team members to read team resources
allow if {
    input.method == "GET"
    input.path = ["api", "v1", "teams", team_id, _]
    input.user.team_memberships[_].team_id == team_id
}

# Rate limiting check
rate_limit_exceeded if {
    input.rate_limit.requests_per_minute > 100
}

deny["rate limit exceeded"] if {
    rate_limit_exceeded
}

# secrets.tf - AWS Secrets Manager configuration

# Database credentials with rotation
resource "aws_secretsmanager_secret" "db_credentials" {
  name        = "production/api/database"
  description = "Production database credentials"
  kms_key_id  = aws_kms_key.secrets.arn

  tags = {
    Environment = "production"
    Application = "api"
  }
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "api_user"
    password = random_password.db_password.result
    host     = aws_db_instance.main.address
    port     = 5432
    database = "api"
  })
}

# Automatic rotation
resource "aws_secretsmanager_secret_rotation" "db_rotation" {
  secret_id           = aws_secretsmanager_secret.db_credentials.id
  rotation_lambda_arn = aws_lambda_function.rotate_secret.arn

  rotation_rules {
    automatically_after_days = 30
  }
}

# KMS key for encryption
resource "aws_kms_key" "secrets" {
  description             = "KMS key for secrets encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM policies"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow Secrets Manager"
        Effect = "Allow"
        Principal = {
          Service = "secretsmanager.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:GenerateDataKey*"
        ]
        Resource = "*"
      }
    ]
  })
}

# IAM policy for application access
resource "aws_iam_policy" "secrets_access" {
  name        = "api-secrets-access"
  description = "Allow API to access secrets"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = [
          aws_secretsmanager_secret.db_credentials.arn,
          "arn:aws:secretsmanager:*:*:secret:production/api/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt"
        ]
        Resource = aws_kms_key.secrets.arn
      }
    ]
  })
}

ssl_protocols TLSv1.3 TLSv1.2;
ssl_prefer_server_ciphers off;
ssl_conf_command Ciphersuites TLS_AES_256_GCM_SHA384:TLS_CHACHA20_POLY1305_SHA256:TLS_AES_128_GCM_SHA256;
ssl_ciphers ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384:ECDHE-ECDSA-CHACHA20-POLY1305:ECDHE-RSA-CHACHA20-POLY1305;
ssl_protocols TLSv1.3 TLSv1.2;
ssl_prefer_server_ciphers off;

# TLS 1.3 ciphers (preferred)
ssl_conf_command Ciphersuites TLS_AES_256_GCM_SHA384:TLS_CHACHA20_POLY1305_SHA256:TLS_AES_128_GCM_SHA256;

# TLS 1.2 ciphers (fallback)
ssl_ciphers ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384:ECDHE-ECDSA-CHACHA20-POLY1305:ECDHE-RSA-CHACHA20-POLY1305;

# ECDH curve
ssl_ecdh_curve X25519:secp384r1;

# Session settings
ssl_session_timeout 1d;
ssl_session_cache shared:SSL:50m;
ssl_session_tickets off;

# OCSP Stapling
ssl_stapling on;
ssl_stapling_verify on;
resolver 8.8.8.8 8.8.4.4 valid=300s;
resolver_timeout 5s;

# Certificate paths
ssl_certificate /etc/nginx/certs/fullchain.pem;
ssl_certificate_key /etc/nginx/certs/privkey.pem;
ssl_trusted_certificate /etc/nginx/certs/chain.pem;

# DH parameters (if using RSA)
ssl_dhparam /etc/nginx/certs/dhparam.pem;

# Server block
server {
    listen 443 ssl http2;
    listen [::]:443 ssl http2;
    server_name api.yourapp.com;

    # Security headers
    add_header Strict-Transport-Security "max-age=31536000; includeSubDomains; preload" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-Frame-Options "DENY" always;
    add_header X-XSS-Protection "1; mode=block" always;
    add_header Content-Security-Policy "default-src 'self'" always;
    add_header Referrer-Policy "strict-origin-when-cross-origin" always;

    # Hide server version
    server_tokens off;

    location / {
        proxy_pass http://backend;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}

# Redirect HTTP to HTTPS
server {
    listen 80;
    listen [::]:80;
    server_name api.yourapp.com;
    return 301 https://$host$request_uri;
}

// csp-config.js - Content Security Policy configuration

const cspConfig = {
  // Base policies
  directives: {
    // Default - block everything not explicitly allowed
    defaultSrc: ["'self'"],

    // Scripts
    scriptSrc: [
      "'self'",
      "'strict-dynamic'",  // Allow dynamically created scripts if parent is trusted
      // Add nonce for inline scripts: `'nonce-${nonce}'`
    ],

    // Styles
    styleSrc: [
      "'self'",
      "'unsafe-inline'",  // Required for many CSS-in-JS solutions
    ],

    // Images
    imgSrc: [
      "'self'",
      "data:",
      "https://cdn.yourapp.com",
      "https://*.gravatar.com",
    ],

    // Fonts
    fontSrc: [
      "'self'",
      "https://fonts.gstatic.com",
    ],

    // Connections (fetch, XHR, WebSocket)
    connectSrc: [
      "'self'",
      "https://api.yourapp.com",
      "wss://realtime.yourapp.com",
      "https://analytics.yourapp.com",
    ],

    // Media (audio, video)
    mediaSrc: [
      "'self'",
      "https://cdn.yourapp.com",
    ],

    // Object, embed, applet
    objectSrc: ["'none'"],

    // Frames
    frameSrc: [
      "'self'",
      "https://www.youtube.com",
      "https://player.vimeo.com",
    ],

    // Frame ancestors (who can embed this page)
    frameAncestors: ["'self'"],

    // Form submissions
    formAction: ["'self'"],

    // Base URI
    baseUri: ["'self'"],

    // Upgrade insecure requests
    upgradeInsecureRequests: [],

    // Block mixed content
    blockAllMixedContent: [],

    // Report violations
    reportUri: ["/api/csp-report"],
    reportTo: ["csp-endpoint"],
  },

  // Report-Only mode for testing
  reportOnly: false,
};

// Express middleware
function cspMiddleware(req, res, next) {
  const nonce = crypto.randomBytes(16).toString('base64');
  res.locals.cspNonce = nonce;

  const directives = { ...cspConfig.directives };
  directives.scriptSrc = [...directives.scriptSrc, `'nonce-${nonce}'`];

  const cspHeader = Object.entries(directives)
    .map(([key, values]) => {
      const directive = key.replace(/([A-Z])/g, '-$1').toLowerCase();
      return `${directive} ${values.join(' ')}`;
    })
    .join('; ');

  const headerName = cspConfig.reportOnly
    ? 'Content-Security-Policy-Report-Only'
    : 'Content-Security-Policy';

  res.setHeader(headerName, cspHeader);
  next();
}

storage "raft" {
  path    = "/vault/data"
  node_id = "vault-1"
}

listener "tcp" {
  address         = "0.0.0.0:8200"
  tls_cert_file   = "/vault/certs/vault.crt"
  tls_key_file    = "/vault/certs/vault.key"
  tls_min_version = "tls13"
}

# Application policy
path "secret/data/{{identity.entity.aliases.auth_kubernetes_*.metadata.service_account_namespace}}/*" {
  capabilities = ["read"]
}

path "database/creds/{{identity.entity.aliases.auth_kubernetes_*.metadata.service_account_name}}" {
  capabilities = ["read"]
}

# Admin policy
path "secret/*" {
  capabilities = ["create", "read", "update", "delete", "list"]
}

path "database/*" {
  capabilities = ["create", "read", "update", "delete", "list"]
}

# PKI policy
path "pki/issue/web-certs" {
  capabilities = ["create", "update"]
}

// security-headers.js - Complete security headers configuration

const helmet = require('helmet');

const securityHeaders = helmet({
  // Content Security Policy
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'", "'strict-dynamic'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", "data:", "https:"],
      connectSrc: ["'self'", "https://api.yourapp.com"],
      fontSrc: ["'self'", "https://fonts.gstatic.com"],
      objectSrc: ["'none'"],
      frameAncestors: ["'self'"],
      formAction: ["'self'"],
      upgradeInsecureRequests: [],
    },
  },

  // Strict Transport Security
  strictTransportSecurity: {
    maxAge: 31536000,  // 1 year
    includeSubDomains: true,
    preload: true,
  },

  // X-Content-Type-Options
  xContentTypeOptions: true,  // nosniff

  // X-Frame-Options
  xFrameOptions: { action: 'deny' },

  // X-XSS-Protection (legacy, but still useful)
  xXssProtection: true,

  // Referrer-Policy
  referrerPolicy: {
    policy: 'strict-origin-when-cross-origin',
  },

  // Permissions-Policy (formerly Feature-Policy)
  permittedCrossDomainPolicies: false,

  // DNS Prefetch Control
  dnsPrefetchControl: { allow: false },

  // Download Options (IE)
  xDownloadOptions: true,

  // Powered-By (remove)
  xPoweredBy: false,

  // Origin-Agent-Cluster
  originAgentCluster: true,

  // Cross-Origin headers
  crossOriginEmbedderPolicy: { policy: 'require-corp' },
  crossOriginOpenerPolicy: { policy: 'same-origin' },
  crossOriginResourcePolicy: { policy: 'same-origin' },
});

module.exports = securityHeaders;
